Here's the full implementation:

### XAML

```xml
<RefreshView IsRefreshing="{Binding IsRefreshing}"
             Command="{Binding RefreshCommand}">
    <CollectionView ItemsSource="{Binding Items}"
                    SelectionMode="Single"
                    SelectedItem="{Binding CurrentItem, Mode=TwoWay}"
                    SelectionChangedCommand="{Binding ItemSelectedCommand}">
        <CollectionView.ItemTemplate>
            <DataTemplate x:DataType="models:Item">
                <Grid Padding="12" ColumnDefinitions="48,*" ColumnSpacing="12">
                    <Image Source="{Binding Icon}" WidthRequest="40" HeightRequest="40" />
                    <Label Grid.Column="1" Text="{Binding Name}" VerticalOptions="Center" />
                </Grid>
            </DataTemplate>
        </CollectionView.ItemTemplate>
    </CollectionView>
</RefreshView>
```

### ViewModel

```csharp
public partial class ItemsViewModel : ObservableObject
{
    private readonly IApiService _api;
    private readonly INavigationService _nav;

    [ObservableProperty]
    private bool isRefreshing;

    [ObservableProperty]
    private Item? currentItem;

    public ObservableCollection<Item> Items { get; } = new();

    [RelayCommand]
    private async Task RefreshAsync()
    {
        var data = await _api.GetItemsAsync();
        MainThread.BeginInvokeOnMainThread(() =>
        {
            Items.Clear();
            foreach (var item in data)
                Items.Add(item);
        });
        IsRefreshing = false;   // stops the spinner
    }

    [RelayCommand]
    private async Task ItemSelectedAsync()
    {
        if (CurrentItem is null) return;
        await _nav.GoToAsync("DetailPage", new Dictionary<string, object>
        {
            ["Item"] = CurrentItem
        });
        CurrentItem = null;     // reset so re-selection works
    }
}
```

### Key bindings explained

| Property | Binding | Purpose |
|---|---|---|
| `IsRefreshing` | `TwoWay` (default on `RefreshView`) | Controls the refresh spinner; set `false` when done |
| `Command` on `RefreshView` | `RefreshCommand` | Fires `RefreshAsync` to reload from API |
| `SelectedItem` | `CurrentItem`, `Mode=TwoWay` | Tracks the tapped item |
| `SelectionChangedCommand` | `ItemSelectedCommand` | Fires `ItemSelectedAsync` to navigate |

**Important details:**
- Use `ObservableCollection<T>` (not `List<T>`) so UI updates on add/remove.
- Set `CurrentItem = null` after navigation so the same item can be re-selected.
- Set `IsRefreshing = false` when the refresh completes to dismiss the spinner.
- Set `x:DataType` on `DataTemplate` for compiled bindings.
